import{_ as t,a}from"./chunks/填写github渠道配置.B-S0-llS.js";import{_ as s,o as n,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"GitHub Releases Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/github-releases.md","filePath":"ta/upload/github-releases.md","lastUpdated":1781962217000}'),r={name:"ta/upload/github-releases.md"};function l(d,e,c,p,h,u){return n(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="github-releases-channel-சேர்க்கவும்" tabindex="-1">GitHub Releases Channel சேர்க்கவும் <a class="header-anchor" href="#github-releases-channel-சேர்க்கவும்" aria-label="Permalink to &quot;GitHub Releases Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="தொடங்குவதற்கு-முன்-தேவையானவை" tabindex="-1">தொடங்குவதற்கு முன் தேவையானவை <a class="header-anchor" href="#தொடங்குவதற்கு-முன்-தேவையானவை" aria-label="Permalink to &quot;தொடங்குவதற்கு முன் தேவையானவை&quot;">​</a></h2><p>மூன்று விஷயங்கள் மட்டும்:</p><table tabindex="0"><thead><tr><th>தேவை</th><th>பயன்பாடு</th></tr></thead><tbody><tr><td>GitHub account</td><td>access token உருவாக்கவும் repository own செய்யவும்</td></tr><tr><td>GitHub Access Token</td><td>ImgBed GitHub API அணுக, releases உருவாக்க, files upload செய்ய</td></tr><tr><td>Repository name</td><td>repository name மட்டும் கொடுக்கலாம், உதா. <code>image</code></td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-github-ல்-sign-in-செய்து-access-token-உருவாக்கவும்" tabindex="-1">Step 1: GitHub-ல் Sign in செய்து Access Token உருவாக்கவும் <a class="header-anchor" href="#step-1-github-ல்-sign-in-செய்து-access-token-உருவாக்கவும்" aria-label="Permalink to &quot;Step 1: GitHub-ல் Sign in செய்து Access Token உருவாக்கவும்&quot;">​</a></h3><ol><li>GitHub-ல் sign in செய்யவும்.</li><li>மேல் வலது மூலையில் avatar கிளிக் செய்து <code>Settings</code> திறக்கவும்.</li><li>left sidebar-ல் <code>Developer settings</code> திறக்கவும்.</li><li><code>Personal access tokens</code> திறக்கவும்.</li><li><code>Tokens (classic)</code> திறக்கவும்.</li><li><code>Generate new token (classic)</code> கிளிக் செய்யவும்.</li><li>token-க்கு அடையாளம் காண எளிதான பெயர் கொடுக்கவும்.</li><li>maintenance preference படி expiration date தேர்வு செய்யவும்.</li><li><code>repo</code> மற்றும் <code>workflow</code> scopes தேர்வு செய்யவும்.</li><li>token உருவானதும் உடனே copy செய்து சேமிக்கவும்.</li></ol><p><img src="'+t+'" alt="Add GitHub permissions" loading="lazy"></p><h2 id="step-2-imgbed-ல்-github-releases-channel-நிரப்பவும்" tabindex="-1">Step 2: ImgBed-ல் GitHub Releases Channel நிரப்பவும் <a class="header-anchor" href="#step-2-imgbed-ல்-github-releases-channel-நிரப்பவும்" aria-label="Permalink to &quot;Step 2: ImgBed-ல் GitHub Releases Channel நிரப்பவும்&quot;">​</a></h2><p>Upload Settings-ல் <code>GitHub Releases</code> தேர்வு செய்த பிறகு:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>What to Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>உங்கள் பெயர், உதா. <code>GitHubPrimary</code>.</td></tr><tr><td>Access Token</td><td>இப்போது உருவாக்கிய GitHub Personal Access Token.</td></tr><tr><td>Repository name</td><td>short repo name <code>image</code>, அல்லது full path <code>username/image</code>.</td></tr><tr><td>Private repository</td><td>தேவைக்கேற்ப on/off.</td></tr><tr><td>Remark</td><td>optional, உதா. <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+a+`" alt="Fill in the GitHub channel configuration" loading="lazy"></p><h2 id="step-3-channel-save-செய்யவும்" tabindex="-1">Step 3: Channel Save செய்யவும் <a class="header-anchor" href="#step-3-channel-save-செய்யவும்" aria-label="Permalink to &quot;Step 3: Channel Save செய்யவும்&quot;">​</a></h2><p>fields நிரப்பிய பிறகு Save கிளிக் செய்யவும்.</p><p>system இதை தானாக கையாளும்:</p><table tabindex="0"><thead><tr><th>System Behavior</th><th>Description</th></tr></thead><tbody><tr><td>Short repository name</td><td>ImgBed current GitHub account கண்டறிந்து full repository path ஆக expand செய்கிறது.</td></tr><tr><td>Full repository path</td><td><code>username/repository</code> path-ஐ உள்ளிட்டபடியே பயன்படுத்தும்.</td></tr><tr><td>Repository check</td><td>current personal account path என்றால் repository இல்லாதபோது ImgBed தானாக create செய்யும். full path manual என்றால் அதையே பயன்படுத்தும்.</td></tr><tr><td>Public/private state</td><td>repository visibility current switch படி synchronized ஆகும்.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><p>GitHub Releases flow:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub-ல் sign in செய்யவும்</span></span>
<span class="line"><span>-&gt; Access Token உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; ImgBed-க்கு திரும்பி token மற்றும் repository name நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; repo name மட்டும் இருந்தால் ImgBed current username சேர்க்கும்</span></span>
<span class="line"><span>-&gt; username/repo இருந்தால் அதையே பயன்படுத்தும்</span></span>
<span class="line"><span>-&gt; test image upload செய்யவும்</span></span></code></pre></div>`,19)])])}const k=s(r,[["render",l]]);export{g as __pageData,k as default};
